use std::sync::atomic::{AtomicBool, Ordering};
use std::thread;
use std::time::Duration;

struct Worker {
    running: AtomicBool,
}

impl Worker {
    fn new() -> Self {
        Worker { running: AtomicBool::new(true) }
    }

    fn stop(&self) {
        self.running.store(false, Ordering::SeqCst);
    }

    fn process_loop(&self) {
        println!("Worker thread started.");
        while self.running.load(Ordering::SeqCst) || self.is_still_processing() {
            if !self.running.load(Ordering::SeqCst) && !self.is_still_processing() {
                break;
            }
            println!("Processing request cycle...");
            thread::sleep(Duration::from_millis(500));
        }
        println!("Worker thread finished cleanup.");
    }

    fn is_still_processing(&self) -> bool {
        true
    }
}

fn main() {
    let worker = Worker::new();
    let worker_clone = worker.clone();
    let handle = thread::spawn(move || {
        worker_clone.process_loop();
    });

    println!("Main thread simulating work for 2 seconds...");
    thread::sleep(Duration::from_secs(2));

    println!("Main thread initiating shutdown sequence.");
    worker.stop();

    thread::sleep(Duration::from_millis(100));

    handle.join().expect("Failed to join worker thread");
}

impl Clone for Worker {
    fn clone(&self) -> Self {
        Worker { running: AtomicBool::new(true) }
    }
}

use tokio::signal;
use std::time::Duration;
use futures::future::select_all;

#[derive(Debug)]
struct WebhookJob {
    url: String,
    attempt: u32,
}

async fn dispatch_job(job: &WebhookJob) -> Result<(), String> {
    println!("Attempting to send webhook to {} (Attempt {})", job.url, job.attempt);
    tokio::time::sleep(Duration::from_millis(100)).await;
    if job.attempt >= 3 {
        return Err(format!("Failed permanently after multiple retries for {}", job.url));
    }
    Ok(())
}

async fn run_dispatcher() -> Result<(), Box<dyn std::error::Error>> {
    let initial_job = WebhookJob { url: "http://example.com/hook".to_string(), attempt: 1 };
    let mut jobs_to_process = vec![initial_job];

    loop {
        tokio::select! {
            _ = signal::ctrl_c() => {
                println!("Received shutdown signal, beginning graceful exit.");
                break;
            }
            else => {}
        }

        if jobs_to_process.is_empty() {
            println!("No jobs scheduled. Waiting...");
            tokio::time::sleep(Duration::from_secs(2)).await;
            continue;
        }

        let job = jobs_to_process.remove(0);
        match dispatch_job(&job).await {
            Ok(_) => println!("Successfully dispatched job to {}.", job.url),
            Err(e) => {
                println!("Job failed: {}. Scheduling retry with backoff.", e);
                let next_attempt = job.attempt + 1;
                if next_attempt <= 5 {
                    let next_job = WebhookJob { url: job.url, attempt: next_attempt };
                    tokio::time::sleep(Duration::from_millis(500 * (next_attempt as u64))).await;
                    jobs_to_process.push(next_job);
                } else {
                    println!("Job permanently failed after max retries.");
                }
            }
        }
    }
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    run_dispatcher().await?;
    println!("Dispatcher shut down cleanly.");
    Ok(())
}

use std::sync::{atomic::{AtomicBool, Ordering}, Arc};
use std::thread;
use std::time::Duration;

struct Worker {
    id: i32,
    should_stop: Arc<AtomicBool>,
}

impl Worker {
    fn new(id: i32, should_stop: Arc<AtomicBool>) -> Self {
        Worker { id, should_stop }
    }

    fn run(&self) {
        loop {
            if self.should_stop.load(Ordering::Relaxed) {
                println!("Worker {} received stop signal and is exiting.", self.id);
                break;
            }
            println!("Worker {} processing data chunk...", self.id);
            thread::sleep(Duration::from_millis(100));
        }
    }
}

fn main() {
    let stop_flag = Arc::new(AtomicBool::new(false));
    let num_workers = 3;
    let mut handles = vec![];

    for i in 0..num_workers {
        let worker = Worker::new(i + 1, Arc::clone(&stop_flag));
        let handle = thread::spawn(move || { worker.run(); });
        handles.push(handle);
    }

    println!("Main loop running for 2 seconds...");
    thread::sleep(Duration::from_secs(2));

    println!("nSending graceful shutdown signal to all workers...");
    stop_flag.store(true, Ordering::Relaxed);

    for handle in handles {
        handle.join().expect("Could not join worker thread");
    }

    println!("All workers joined successfully. Application shutting down.");
}
